#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    bool solve(int n, vector<long long>& val, vector<int>& left, vector<int>& right) {
        const long long INF = 4e18; // larger than any possible value
        struct NodeInfo {int idx; long long lo; long long hi;};
        vector<NodeInfo> st;
        st.reserve(n);
        st.push_back({1, -INF, INF});
        while (!st.empty()) {
            NodeInfo cur = st.back();
            st.pop_back();
            int idx = cur.idx;
            if (idx == -1) continue;
            long long v = val[idx];
            if (!(cur.lo < v && v < cur.hi)) return false;
            if (right[idx] != -1) st.push_back({right[idx], v, cur.hi});
            if (left[idx] != -1) st.push_back({left[idx], cur.lo, v});
        }
        return true;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<long long> val(n + 1);
    vector<int> left(n + 1), right(n + 1);
    for (int i = 1; i <= n; ++i) {
        long long v; int l, r;
        cin >> v >> l >> r;
        val[i] = v;
        left[i] = l;
        right[i] = r;
    }
    Solution sol;
    bool ok = sol.solve(n, val, left, right);
    cout << (ok ? "YES" : "NO") << "\n";
    return 0;
}
